// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Navigate', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Navigate', async function() {
    // Test name: Navigate
    // Step # | name | target | value
    // 1 | open | /home | 
    await driver.get("http://localhost:4200//home");

    // 2 | setWindowSize | 1360x768 | 
    await driver.manage().window().setRect({ width: 1360, height: 768 });

    // 3 | assertText | xpath=//div[@id='root']/section/section/main/div/h3 | ナビゲーション
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/div/h3")).getText() == "ナビゲーション");

    // 4 | executeScript | return getComputedStyle(document.getElementsByClassName("ant-typography")[0]).color | title_color
    vars["title_color"] = await driver.executeScript("return getComputedStyle(document.getElementsByClassName(\"ant-typography\")[0]).color");

    // 5 | assert | title_color | rgb(0, 135, 77)
    assert(vars["title_color"].toString() == "rgb(0, 135, 77)");

    // 6 | mouseOver | css=.ant-row:nth-child(2) .ant-card-body | 
    {
      const element = await driver.findElement(By.css(".ant-row:nth-child(2) .ant-card-body"));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }

    // 7 | executeScript | return getComputedStyle(document.getElementsByClassName("ant-card ant-card-bordered section_card css-dev-only-do-not-override-ph9edi")[0]).backgroundColor | backgroundColor1
    vars["backgroundColor1"] = await driver.executeScript("return getComputedStyle(document.getElementsByClassName(\"ant-card ant-card-bordered section_card css-dev-only-do-not-override-ph9edi\")[0]).backgroundColor");

    // 8 | assert | backgroundColor1 | rgb(0, 168, 95)
    assert(vars["backgroundColor1"].toString() == "rgb(0, 168, 95)");

    // 9 | assertText | xpath=//div[@id='root']/section/section/main/div/div/div/div | 被評価者
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/div/div/div/div")).getText() == "被評価者");

    // 10 | assertText | xpath=//div[@id='root']/section/section/main/div/div[2]/div/div | 評価者
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/div/div[2]/div/div")).getText() == "評価者");
  });
});
